+/// Result of evaluating a single gate.
+#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
+pub struct GateEvaluation {
+    pub gate: GateKind,
+    pub passed: bool,
+    pub required: bool,
+    pub evidence: Vec<String>,
+    pub summary: String,
+}
