+impl GateEvaluation {
+    /// Convert to the self_replacement `GateResult` type.
+    pub fn to_gate_result(&self) -> GateResult {
+        GateResult {
+            gate_name: self.gate.as_str().to_string(),
+            passed: self.passed,
+            evidence_refs: self.evidence.clone(),
+            summary: self.summary.clone(),
+        }
+    }
+}
